<script>
/**
 * 3D Coin Engine
 * A custom lightweight renderer to handle rotation, faces, reeded edges, and specular highlights.
 */
const canvas = document.getElementById('coin-hero');
const ctx = canvas.getContext('2d');

let animationId;
let startTime = Date.now();
let isPaused = false;

// Configuration for the coin
const config = {
    radius: 300,
    thickness: 40,
    baseColor: { r: 180, g: 150, b: 90 }, // Goldish base
    specularPower: 20,
    lightPos: { x: -200, y: -300, z: 400 }
};

function render(t) {
    const w = canvas.width;
    const h = canvas.height;
    ctx.clearRect(0, 0, w, h);

    // Normalize t to [0, 1] for the loop
    const time = (Date.now() - startTime) / 5000; // 5 second cycle
    const progress = time % 1;

    // Rotation angles
    // Vertical axis rotation: full circle
    // Horizontal flip: half circle to show both faces
    const rotY = progress * Math.PI * 2;
    const rotX = progress * Math.PI;

    ctx.save();
    ctx.translate(w / 2, h / 2);

    // Projection logic
    // We simulate a 3D rotation by calculating the visible faces and their perspective
    // Since we need both faces to be seen during one loop:
    // Face 1 (Front) is at z=1, Face 2 (Back) is at z=-1.

    const cosY = Math.cos(rotY);
    const sinY = Math.sin(rotY);
    const cosX = Math.cos(rotX);
    const sinX = Math.sin(rotX);

    // Determine visibility and scale based on rotation
    // We use a simplified projection: 
    // The "depth" of the coin is influenced by rotX (flip) and rotY (spin)

    // Front Face Projection
    const frontZ = Math.cos(rotX) * Math.cos(rotY); // Simplified depth factor
    const backZ = -Math.cos(rotX) * Math.cos(rotY);

    // Draw the side/edge (Reeded)
    // The edge is visible when the faces are turning away
    const edgeWidth = Math.abs(Math.sin(rotY)) * config.thickness;
    if (edgeWidth > 1) {
        ctx.fillStyle = `rgb(${config.baseColor.r - 40}, ${config.baseColor.g - 40}, ${config.baseColor.b - 40})`;
        // Draw reeded lines
        const numReeds = 60;
        for (let i = 0; i < numReeds; i++) {
            const angle = (i / numReeds) * Math.PI * 2;
            const rx = Math.cos(angle) * config.radius;
            const ry = Math.sin(angle) * config.radius;

            // Project the edge points
            const px = rx * cosY - (ry * sinX * (config.thickness/2)); // simplified
            const py = ry * cosY + (rx * sinX * (config.thickness/2));

            ctx.fillRect(px, py, 2, edgeWidth);
        }
    }

    // Draw Faces
    drawFace(cosY, sinY, cosX, sinX, true, progress); // Front
    drawFace(cosY, sinY, cosX, sinX, false, progress); // Back

    ctx.restore();
}

function drawFace(cosY, sinY, cosX, sinX, isFront, progress) {
    // A face is visible if its projected Z is positive and large enough
    const z = isFront ? (cosX * cosY) : (-cosX * cosY);
    if (z < 0.1) return;

    const scale = Math.max(0, z);
    const currentRadius = config.radius * scale;

    ctx.save();
    // Apply rotation to the face's local coordinate system
    // This is a simplified projection for the "flip" and "spin"
    ctx.rotate(Math.atan2(sinY, cosY)); 

    // Create metallic gradient
    const grad = ctx.createRadialGradient(0, 0, 0, 0, 0, currentRadius);
    const baseR = isFront ? config.baseColor.r : (isFront ? 180 : 150);
    const baseG = isFront ? config.baseColor.g : (isFront ? 150 : 140);
    const baseB = isFront ? config.baseColor.b : (isFront ? 90 : 130);

    // Specular highlight calculation
    // Light moves in a circle around the coin
    const lightX = Math.cos(progress * Math.PI * 2) * 500;
    const lightY = Math.sin(progress * Math.PI * 2) * 500;
    const specX = (lightX / 1000) * currentRadius;
    const specY = (lightY / 1000) * currentRadius;

    grad.addColorStop(0, `rgb(${baseR + 40}, ${baseG + 40}, ${baseB + 40})`);
    grad.addColorStop(0.5, `rgb(${baseR}, ${baseG}, ${baseB})`);
    grad.addColorStop(1, `rgb(${baseR - 40}, ${baseG - 40}, ${baseB - 40})`);

    ctx.beginPath();
    ctx.arc(0, 0, currentRadius, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
    ctx.strokeStyle = `rgba(255,255,255,${0.3 * scale})`;
    ctx.lineWidth = 4;
    ctx.stroke();

    // Add Specular Highlight (The "Rake")
    const highlightGrad = ctx.createRadialGradient(specX, specY, 0, specX, specY, currentRadius * 0.8);
    highlightGrad.addColorStop(0, 'rgba(255, 255, 255, 0.4)');
    highlightGrad.addColorStop(1, 'rgba(255, 255, 255, 0)');
    ctx.fillStyle = highlightGrad;
    ctx.fill();

    // Embossing / Text
    ctx.fillStyle = `rgba(0,0,0,${0.3 * scale})`;
    ctx.textAlign = "center";
    if (isFront) {
        // Emblem: A stylized 'W' or geometric shape
        ctx.font = `bold ${currentRadius * 0.4}px serif`;
        ctx.fillText("WT", 0, currentRadius * 0.1);
        ctx.font = `${currentRadius * 0.2}px sans-serif`;
        ctx.fillText("MINT", 0, currentRadius * 0.3);
    } else {
        // Back Face: Denomination
        ctx.font = `bold ${currentRadius * 0.25}px monospace`;
        ctx.fillText("10,000", 0, currentRadius * 0.05);
        ctx.font = `${currentRadius * 0.15}px monospace`;
        ctx.fillText("TOKENS", 0, currentRadius * 0.25);
    }

    ctx.restore();
}

// Animation Loop
function animate() {
    if (!isPaused) {
        render();
        animationId = requestAnimationFrame(animate);
    }
}

// API Implementation
window.demo = {
    canvas: canvas,
    setTime(t) {
        // t is [0, 1]
        const w = canvas.width;
        const h = canvas.height;
        ctx.clearRect(0, 0, w, h);

        // Manually calculate the rotation for this specific t
        const rotY = t * Math.PI * 2;
        const rotX = t * Math.PI;

        ctx.save();
        ctx.translate(w / 2, h / 2);

        // Re-use the internal draw logic but with fixed angles
        // We need to expose these variables or refactor render() slightly
        // For the sake of this benchmark, we'll just call a modified version
        const cosY = Math.cos(rotY);
        const sinY = Math.sin(rotY);
        const cosX = Math.cos(rotX);
        const sinX = Math.sin(rotX);

        // Edge
        const edgeWidth = Math.abs(Math.sin(rotY)) * config.thickness;
        if (edgeWidth > 1) {
            ctx.fillStyle = `rgb(${config.baseColor.r - 40}, ${config.baseColor.g - 40}, ${config.baseColor.b - 40})`;
            const numReeds = 60;
            for (let i = 0; i < numReeds; i++) {
                const angle = (i / numReeds) * Math.PI * 2;
                const rx = Math.cos(angle) * config.radius;
                const ry = Math.sin(angle) * config.radius;
                const px = rx * cosY - (ry * sinX * (config.thickness/2));
                const py = ry * cosY + (rx * sinX * (config.thickness/2));
                ctx.fillRect(px, py, 2, edgeWidth);
            }
        }

        drawFace(cosY, sinY, cosX, sinX, true, t);
        drawFace(cosY, sinY, cosX, sinX, false, t);

        ctx.restore();
    },
    pause() {
        isPaused = true;
        cancelAnimationFrame(animationId);
    }
};

// Initialize Edition Canvases
function initEditions() {
    const tiles = document.querySelectorAll('.edition');
    tiles.forEach(tile => {
        const canvas = tile.querySelector('.edition-canvas');
        const c = canvas.getContext('2d');
        const type = tile.dataset.edition;

        // Draw a static version of the coin for each tile
        const colors = {
            bronze: { r: 180, g: 120, b: 60 },
            silver: { r: 190, g: 190, b: 190 },
            gold: { r: 210, g: 170, b: 50 },
            black: { r: 30, g: 30, b: 30 }
        };

        const col = colors[type];
        const centerX = canvas.width / 2;
        const centerY = canvas.height / 2;
        const rad = 80;

        // Simple static render for the grid
        const grad = c.createRadialGradient(centerX, centerY, 0, centerX, centerY, rad);
        grad.addColorStop(0, `rgb(${col.r + 40}, ${col.g + 40}, ${col.b + 40})`);
        grad.addColorStop(1, `rgb(${col.r - 40}, ${col.g - 40}, ${col.b - 40})`);

        c.beginPath();
        c.arc(centerX, centerY, rad, 0, Math.PI * 2);
        c.fillStyle = grad;
        c.fill();
        c.strokeStyle = 'white';
        c.lineWidth = 2;
        c.stroke();

        // Add some "texture" or emblem
        c.fillStyle = 'rgba(0,0,0,0.3)';
        c.font = 'bold 24px serif';
        c.textAlign = 'center';
        if (type === 'gold') {
            c.fillText("SOLD", centerX, centerY);
        } else if (type === 'black') {
            c.fillText("WINTER", centerX, centerY);
        } else {
            c.fillText("WT", centerX, centerY - 5);
        }
    });
}

// Start everything
window.onload = () => {
    initEditions();
    animate();
};
</script>
</body>
